export const CONTENT_HTML = "\r\n<p class=\"intro\">Bạn ngồi xuống trước một mẫu, cầm chì lên, và... bắt đầu vẽ từ đâu? Với người mới, đây là câu hỏi khó nhất. <strong>Phương pháp vẽ giới hạn</strong> là câu trả lời đơn giản nhất — và hiệu quả nhất để bắt đầu.</p>\r\n\r\n<div class=\"stats break-half\">\r\n  <div class=\"stat\"><div class=\"stat-num\">01</div><div class=\"stat-label\">PP đầu tiên</div><div class=\"stat-sub\">Cho người nhập môn</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">5'</div><div class=\"stat-label\">Một bài sketch</div><div class=\"stat-sub\">Đủ để dựng hình</div></div>\r\n  <div class=\"stat\"><div class=\"stat-num\">80%</div><div class=\"stat-label\">Độ chính xác</div><div class=\"stat-sub\">Nếu làm đúng</div></div>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>01</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Định nghĩa</p>\r\n    <h2 class=\"div-title\">Vẽ giới hạn là gì?</h2>\r\n  </div>\r\n</div>\r\n\r\n<p><strong>Phương pháp vẽ giới hạn</strong> <em>(Contour Drawing)</em> là kỹ thuật dựng hình bằng cách tập trung vào <strong>đường bao ngoài</strong> của đối tượng, bỏ qua toàn bộ chi tiết bên trong ở giai đoạn đầu. Mục tiêu: bắt được <em>tỉ lệ tổng thể</em> và <em>hình dáng chính</em> nhanh nhất.</p>\r\n\r\n<p>Tại sao hiệu quả? Vì mắt người mới thường \"nhìn chi tiết\" — thấy cái mũi thì vẽ cái mũi, thấy cái tai thì vẽ cái tai. Kết quả: mỗi phần đẹp riêng, nhưng tổng thể sai tỉ lệ.</p>\r\n\r\n<div class=\"gls\">\r\n  <p class=\"gls-head\">A — Thuật ngữ liên quan</p>\r\n  <div class=\"gls-body\">\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Contour<small>Đường bao</small></p><p class=\"gls-def\">Đường viền ngoài của vật thể — ranh giới giữa hình và nền.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Silhouette<small>Bóng khối</small></p><p class=\"gls-def\">Hình dạng đặc bên trong đường bao, dạng đơn sắc.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Blind contour<small>Vẽ mù</small></p><p class=\"gls-def\">Vẽ contour mà không nhìn vào giấy — bài tập luyện mắt.</p></div>\r\n    <div class=\"gls-item\"><p class=\"gls-term\">Gesture<small>Dáng thế</small></p><p class=\"gls-def\">Nét phóng nhanh thể hiện chuyển động của đối tượng.</p></div>\r\n  </div>\r\n</div>\r\n\r\n<!-- 🖼️ MOSAIC · Các ví dụ bài contour -->\r\n<div class=\"mosaic\">\r\n  <div class=\"mosaic-big\">\r\n    <img src=\"/img/phuong-phap-ve-gioi-han/mosaic-1.png\" alt=\"Bài contour tĩnh vật\" />\r\n  </div>\r\n  <div class=\"mosaic-small\">\r\n    <img src=\"/img/phuong-phap-ve-gioi-han/mosaic-2.jpg\" alt=\"Blind contour tay\" />\r\n  </div>\r\n  <div class=\"mosaic-small\">\r\n    <img src=\"/img/phuong-phap-ve-gioi-han/mosaic-3.png\" alt=\"Continuous line drawing\" />\r\n  </div>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>02</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Quy trình</p>\r\n    <h2 class=\"div-title\">4 bước thực hành</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Bất kỳ bài vẽ giới hạn nào cũng đi qua 4 bước cơ bản. Làm đủ 4 bước, bạn có một bản dựng hình chính xác 80%:</p>\r\n\r\n<div class=\"el-intro\">\r\n  <div class=\"el-intro-n\">4</div>\r\n  <p class=\"el-intro-t\">Bốn bước tuần tự — đừng bỏ bước nào.</p>\r\n</div>\r\n\r\n<div class=\"el-list\">\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">01</span>\r\n      <p class=\"el-name\">Quan s&#225;t <em>Observe</em></p>\r\n      <p class=\"el-desc\">Nh&#236;n m&#7851;u 30 gi&#226;y tr&#432;&#7899;c khi ch&#7841;m ch&#236;. X&#225;c &#273;&#7883;nh &#273;i&#7875;m cao nh&#7845;t, th&#7845;p nh&#7845;t, tr&#225;i-ph&#7843;i.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"><img src=\"/img/phuong-phap-ve-gioi-han/el-01.png\" alt=\"Quan sát mẫu\" /></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">02</span>\r\n      <p class=\"el-name\">Khung gi&#7899;i h&#7841;n <em>Bounding box</em></p>\r\n      <p class=\"el-desc\">V&#7869; h&#236;nh ch&#7919; nh&#7853;t bao tr&#7885;n &#273;&#7889;i t&#432;&#7907;ng. \"S&#226;n ch&#417;i\" cho c&#225;c n&#233;t ti&#7871;p theo.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"><img src=\"/img/phuong-phap-ve-gioi-han/el-02.png\" alt=\"Khung giới hạn\" /></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">03</span>\r\n      <p class=\"el-name\">&#272;&#432;&#7901;ng bao ch&#237;nh <em>Main contour</em></p>\r\n      <p class=\"el-desc\">&#272;&#225;nh n&#233;t ph&#225;c &#273;&#7875; t&#236;m &#273;&#432;&#7901;ng bao ngo&#224;i l&#7899;n. N&#233;t nh&#7841;t, c&#243; th&#7875; t&#7849;y.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"><img src=\"/img/phuong-phap-ve-gioi-han/el-03.png\" alt=\"Đường bao chính\" /></div>\r\n  </div>\r\n  <div class=\"el-item\">\r\n    <div class=\"el-item-text\">\r\n      <span class=\"el-n\">04</span>\r\n      <p class=\"el-name\">Tinh ch&#7881;nh <em>Refine</em></p>\r\n      <p class=\"el-desc\">So s&#225;nh v&#7899;i m&#7851;u, ch&#7881;nh l&#7841;i c&#225;c &#273;i&#7875;m l&#7879;ch. Khi t&#7881; l&#7879; OK, n&#233;t nh&#7845;n &#273;&#7853;m h&#417;n.</p>\r\n    </div>\r\n    <div class=\"el-item-img\"><img src=\"/img/phuong-phap-ve-gioi-han/el-04.jpg\" alt=\"Tinh chỉnh\" /></div>\r\n  </div>\r\n</div>\r\n\r\n<!-- 🖼️ GALLERY-3 · 3 ví dụ sai lầm thường gặp -->\r\n<div class=\"gallery gallery-3\">\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/phuong-phap-ve-gioi-han/gallery-3-1.jpg\" alt=\"Lỗi sai tỉ lệ\" />\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/phuong-phap-ve-gioi-han/gallery-3-2.jpg\" alt=\"Vẽ chi tiết trước\" />\r\n  </figure>\r\n  <figure class=\"gallery-box\">\r\n    <img src=\"/img/phuong-phap-ve-gioi-han/gallery-3-3.jpg\" alt=\"Nét quá đậm\" />\r\n  </figure>\r\n</div>\r\n\r\n<p>Ba lỗi kinh điển người mới thường gặp. Xem kỹ — nếu bài của bạn giống cái nào, đó chính là chỗ cần sửa.</p>\r\n\r\n<div class=\"pq\">\r\n  <p class=\"pq-text\">Vẽ từ <em>lớn đến nhỏ,</em> từ <em>ngoài vào trong.</em></p>\r\n  <span class=\"pq-cite\">— Nguyên tắc vàng của dựng hình</span>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>03</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Luyện tập</p>\r\n    <h2 class=\"div-title\">Bài tập &amp; mẹo</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Vẽ giới hạn là kỹ năng <strong>luyện mắt</strong> nhiều hơn luyện tay. Bạn càng quan sát chính xác, nét tay càng tự nhiên theo sau.</p>\r\n\r\n<div class=\"tips\">\r\n  <div class=\"tip\"><span class=\"tip-n\">01</span><div class=\"tip-c\"><p class=\"tip-t\">Bài tập blind contour</p><p class=\"tip-d\">Vẽ mà không nhìn vào giấy — chỉ nhìn mẫu. Nét sẽ méo nhưng mắt bạn sẽ nhạy lên đáng kể sau 1 tuần.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">02</span><div class=\"tip-c\"><p class=\"tip-t\">Đo bằng chì</p><p class=\"tip-d\">Giơ chì dọc theo đường ngang của mẫu để so tỉ lệ. Ví dụ chiều ngang bằng 2 chiều dọc của đầu.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">03</span><div class=\"tip-c\"><p class=\"tip-t\">Vẽ 10 bài contour / ngày</p><p class=\"tip-d\">Mỗi bài 3-5 phút thôi. Mục tiêu là số lượng, không phải độ hoàn chỉnh.</p></div></div>\r\n  <div class=\"tip\"><span class=\"tip-n\">04</span><div class=\"tip-c\"><p class=\"tip-t\">So sánh bằng lưới</p><p class=\"tip-d\">Chụp ảnh bài và mẫu, phủ lưới 3x3 lên cả hai. Lỗi sẽ hiện ngay.</p></div></div>\r\n</div>\r\n\r\n<div class=\"dd break-half\">\r\n  <div class=\"dd-col good\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">+</span><span class=\"dd-title\">Nên làm</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Luôn bắt đầu bằng khung giới hạn</li>\r\n      <li>Nét sketch ban đầu mờ, có thể tẩy</li>\r\n      <li>Nhìn mẫu 80%, nhìn giấy 20%</li>\r\n      <li>Chấp nhận bài đầu xấu — đó là phần của quá trình</li>\r\n    </ul>\r\n  </div>\r\n  <div class=\"dd-col bad\">\r\n    <div class=\"dd-head\"><span class=\"dd-badge\">−</span><span class=\"dd-title\">Nên tránh</span></div>\r\n    <ul class=\"dd-list\">\r\n      <li>Nhảy thẳng vào vẽ chi tiết mắt, mũi</li>\r\n      <li>Nét đầu tiên đã đậm, không thể sửa</li>\r\n      <li>Dán mắt vào giấy, không nhìn mẫu</li>\r\n      <li>Dùng tẩy quá nhiều — càng tẩy càng sai</li>\r\n    </ul>\r\n  </div>\r\n</div>\r\n\r\n\r\n<!-- 05 · UNG DUNG -->\r\n<div class=\"div-sec\" id=\"sec-5\">\r\n  <div class=\"div-num\"><em>05</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Ứng dụng</p>\r\n    <h2 class=\"div-title\">Ba môn thực hành</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Lỽ thuyết cơ sở tạo hình không đứng một mình. Nó là đầu vào trực tiếp cho 3 môn thực hành trọng yếu:</p>\r\n\r\n<div class=\"subj-row break-half\">\r\n  <div class=\"subj hh\" style=\"background-image:url(/img/co-so-tao-hinh/subj-01-hh.jpg);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Khối V</span>\r\n    <h4>Hình họa</h4>\r\n  </div>\r\n  <div class=\"subj tt\" style=\"background-image:url(/img/co-so-tao-hinh/subj-02-bc.png);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Khối H</span>\r\n    <h4>Bố cục màu</h4>\r\n  </div>\r\n  <div class=\"subj tt\" style=\"background-image:url(/img/co-so-tao-hinh/subj-03-tt.jpg);background-size:cover;background-position:center\">\r\n    <span class=\"subj-tag\">Nền tảng</span>\r\n    <h4>Trang trí màu</h4>\r\n  </div>\r\n</div>\r\n\r\n<!-- 06 · LO TRINH -->\r\n<div class=\"div-sec\" id=\"sec-6\">\r\n  <div class=\"div-num\"><em>06</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">Lộ trình</p>\r\n    <h2 class=\"div-title\">12–24 tháng luyện thi</h2>\r\n  </div>\r\n</div>\r\n\r\n<p>Với học sinh chuẩn bị thi khối H, V, lộ trình hợp lý kéo dài <strong>12–24 tháng</strong>:</p>\r\n\r\n<div class=\"tl\">\r\n  <div class=\"tl-item s1\">\r\n    <p class=\"tl-label\">Giai đợan 1 · 3 tháng</p>\r\n    <h4 class=\"tl-title\">Nhập môn</h4>\r\n    <p class=\"tl-desc\">Làm quen yếu tố cơ bản qua bài tập đường nét, hình khối đơn giản. Rèn thói quen quan sát tứ lệ, nhìn sáng tối.</p>\r\n  </div>\r\n  <div class=\"tl-item s2\">\r\n    <p class=\"tl-label\">Giai đợan 2 · 6–12 tháng</p>\r\n    <h4 class=\"tl-title\">Chuyên sâu</h4>\r\n    <p class=\"tl-desc\">Tách nhánh theo mục tiêu. Khối V tập trung tĩnh vật, tượng, người mẫu. Khối H tập trung trang trí màu và sáng tác bố cục.</p>\r\n  </div>\r\n  <div class=\"tl-item s3\">\r\n    <p class=\"tl-label\">Giai đợan 3 · 3–6 tháng</p>\r\n    <h4 class=\"tl-title\">Luyện thi</h4>\r\n    <p class=\"tl-desc\">Làm đề cấu trúc thi thật, luyện tốc độ, chấm chéo, phản biện giảng viên.</p>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"key break\">\r\n  <p class=\"key-lbl\">⭐ Điểm mấu chốt</p>\r\n  <p class=\"key-t\">Vẽ giới hạn không phải kỹ thuật — nó là <em>trình tự tư duy.</em></p>\r\n  <p class=\"key-d\">Nắm được trình tự \"lớn trước, nhỏ sau\", bạn có công cụ để dựng bất kỳ vật thể nào — từ quả táo đến người mẫu. Mọi kỹ thuật vẽ nâng cao đều xây trên nền tảng này.</p>\r\n</div>\r\n\r\n<div class=\"div-sec\">\r\n  <div class=\"div-num\"><em>04</em></div>\r\n  <div class=\"div-meta\">\r\n    <p class=\"div-kicker\">FAQ</p>\r\n    <h2 class=\"div-title\">Câu hỏi thường gặp</h2>\r\n  </div>\r\n</div>\r\n\r\n<div class=\"faq\">\r\n  <details open>\r\n    <summary>Mất bao lâu để thành thục phương pháp này?<span class=\"faq-icon\">−</span></summary>\r\n    <p>Hiểu nguyên lý trong 1 buổi. Thành thục thực hành cần 2-4 tuần với 30 phút mỗi ngày. Sau đó trở thành phản xạ.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Có thể bỏ qua bước khung giới hạn không?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Khi đã thành thục, bạn có thể vẽ khung giới hạn \"trong đầu\" thay vì trên giấy. Nhưng với người mới, luôn vẽ trên giấy.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Vẽ giới hạn khác gì với vẽ cấu trúc?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Vẽ giới hạn tập trung vào đường bao ngoài — phù hợp vật 2D, pose nhanh. Vẽ cấu trúc đi sâu vào khối và trục bên trong — cần cho đối tượng phức tạp.</p>\r\n  </details>\r\n  <details>\r\n    <summary>Dùng bút chì gì cho bài contour?<span class=\"faq-icon\">+</span></summary>\r\n    <p>Chì HB hoặc 2B cho giai đoạn sketch — nhạt, dễ tẩy. Khi tinh chỉnh mới chuyển sang 4B hoặc 6B để nhấn nét đậm.</p>\r\n  </details>\r\n</div>\r\n";

